#include <bits/stdc++.h>
using namespace std;

const int N=2e5+5;

int n,m,a[N],b[502][502];

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=500;j++)
            b[j][i%j]+=a[i];
    while(m--){
        char tp[2];
        int x,y;
        scanf("%s%d%d",tp,&x,&y);
        if(tp[0]=='A'){
            if(x<=500)
                printf("%d\n",b[x][y]);
            else{
                int p=y,sum=0;
                while(p<=n)
                    sum+=a[p],p+=x;
                printf("%d\n",sum);
            }
        }else{
            for(int i=1;i<=500;i++)
                b[i][x%i]+=y-a[x];
            a[x]=y;
        }
    }
    return 0;
}
